CREATE OR REPLACE FUNCTION public.set_selectable_on_create()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN

    PERFORM set_config('search_path', TG_TABLE_SCHEMA, true);

    IF NEW.protected = true THEN

        -- set current selectable to false
        NEW.selectable = false;

    ELSE

        -- set current selectable to true
        NEW.selectable = true;

    END IF;

    RETURN NEW;
END;
$function$
